sql:
SELECT SUM(time_spent) AS total_time_spent
FROM user_activity
WHERE user_id = 1 AND trial_id = 1;

SELECT trial_id
FROM user_activity
WHERE time_spent = (
  SELECT MAX(time_spent)
  FROM user_activity
);

SELECT DISTINCT trial_id
FROM user_activity
WHERE user_id = 1;

SELECT ua.trial_id
FROM user_activity ua
WHERE ua.time_spent >= (
    SELECT AVG(ua2.time_spent)
    FROM user_activity ua2
);

SELECT trial_id, user_id
FROM trials
WHERE trial_id = 1;

